-- W1.6 questions batch 363/9310 (10)

INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-6f0ba476-moex-00050', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '丙成年後得本生父母甲、乙之同意，由丁、戊共同收養。嗣後丁遇車禍身亡。下列關於收養終止 之敘述，何者錯誤？', '["丁、戊僅限於離婚之事由，丙始得單獨與戊合意終止收養", "戊對丙為虐待者，丙亦得聲請法院宣告終止與戊之收養關係", "丙與戊合意終止收養後，丙亦得聲請法院許可終止與丁之收養關係", "戊因與丙終止收養而生活陷於困難，原則上得請求丙給與相當之金額"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:52+00:00", "source_pdf_sha1": "c3d287d292c9", "answer_pdf_sha1": "5eea37b6cb02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00051', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲女未婚生子乙，乙之生父為丙。下列關於認領之敘述，何者正確？', '["甲得請求丙認領乙，但甲應於乙出生後5年間為之", "丙得主動認領乙，但丙應自知悉乙為其非婚生子女之時起7年內為之", "丙仍活著時，乙得請求丙認領，但乙應於成年後2年間為之", "設丙已死亡，丙有繼承人，乙得向丙之繼承人提起強制認領之訴"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:52+00:00", "source_pdf_sha1": "c3d287d292c9", "answer_pdf_sha1": "5eea37b6cb02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00052', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '被繼承人甲與乙係夫妻，乙妻早於甲夫死亡，甲死亡後留有遺產新臺幣（下同）1,500萬元，甲、 乙生前育有2子丙、丁；丙於甲死亡後依法拋棄繼承，丙有1女戊，另乙婚前即育有1子己，甲、 乙婚後，甲未收養己。下列何人有繼承權或代位繼承權，其應繼財產若干？', '["丁有繼承權，戊及己有代位繼承權；丁、戊、己各得500萬元", "丁有繼承權，戊有代位繼承權，己無代位繼承權；丁、戊各得750萬元", "丁有繼承權，戊無代位繼承權，己有代位繼承權；丁、己各得750萬元", "丁為唯一繼承人，得繼承遺產之全部1,500萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:52+00:00", "source_pdf_sha1": "c3d287d292c9", "answer_pdf_sha1": "5eea37b6cb02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00053', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '下列何種情況，繼承人喪失其繼承權？', '["繼承人變造遺囑中所指定之未成年子女監護人", "被繼承人自書遺囑並簽名，繼承人補填其未記明之年月日", "繼承人對被繼承人有重大侮辱之行為，經被繼承人於未經公證之書面中表示使其喪失繼承權", "繼承人故意殺害被繼承人，被繼承人未致死，經法院為免訴之判決"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:52+00:00", "source_pdf_sha1": "c3d287d292c9", "answer_pdf_sha1": "5eea37b6cb02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00054', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲未婚無子，父母、祖父母均已死亡。有一兄，但已死亡。甲生前扶養其兄之未成年子乙。甲死 亡時，留有新臺幣（下同）200萬元之現金，但對丙負有100萬元債務。甲立遺囑遺贈丁100萬 元。乙經親屬會議決議酌給50萬元。乙、丙、丁得自甲之遺產，分別獲得多少金額？', '["乙0元、丙100萬元、丁100萬元", "乙50萬元、丙100萬元、丁50萬元", "乙50萬元、丙50萬元、丁100萬元", "乙25萬元、丙100萬元、丁75萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:52+00:00", "source_pdf_sha1": "c3d287d292c9", "answer_pdf_sha1": "5eea37b6cb02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00055', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'essay', '某甲為中華民國境內居住者，在民國100年買進取得臺北市房屋一棟（供
自住使用），民國114 年以新臺幣 2,000 萬元賣出，若買進價格已無法查
得。某乙為中華民國境內居住者，在民國 110 年以新臺幣 1,000 萬元買
進取得高雄市房屋一棟（供自住使用），民國114年以新臺幣 2,000 萬元
賣出。請依所得稅法、土地稅法規定說明甲、乙兩人賣出房屋時須繳納
那些稅負？又該如何計算？請就土地、房屋分別說明之。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "ebc056a8d8b9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1202", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00056', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'essay', '何謂核課期間？請說明之。又依稅捐稽徵法第 21條規定，請分別說明在
那些情況下核課期間為 5 年、7年？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "ebc056a8d8b9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1202", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00057', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'single_choice', '某甲發現其臺中市土地民國113年之地價稅稅單計算錯誤，應如何處理？', '["向臺中市國稅局申請查對更正", "向臺中市政府地方稅務局申請查對更正", "向臺中市國稅局申請復查", "向臺中市政府地方稅務局申請復查"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "ebc056a8d8b9", "answer_pdf_sha1": "eec9f9a30014", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00058', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'single_choice', '納稅義務人依法提起訴願，並對復查決定之應納稅額至少繳納若干比例，則稽徵機關可暫緩移送 強制執行？', '["全部", "1/2", "1/3", "1/4"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "ebc056a8d8b9", "answer_pdf_sha1": "eec9f9a30014", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00059', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'single_choice', '依稅捐稽徵法規定，下列何者無法作為擔保稅款之擔保品？', '["銀行存款", "政府發行之公債", "上市櫃有價證券", "不易變價之山坡地"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "ebc056a8d8b9", "answer_pdf_sha1": "eec9f9a30014", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL)
